What does the following program print?

```cpp
#include <iostream>
#include <vector>
int main()
{
    std::vector<int> v { 10, 20, 30, 40 };
    auto it = v.begin();
    ++it;
    std::cout << *it << '\n';
    ++it;
    ++it;
    std::cout << *it << '\n';
    return 0;
}
```

The code below is supposed to double every element of the vector, but it has a bug. What is it?

```cpp
#include <iostream>
#include <vector>
int main()
{
    std::vector<int> v { 1, 2, 3 };
    for (auto it = v.begin(); it != v.end(); ++it)
        it *= 2;   // intended to double each element
    for (auto it = v.begin(); it != v.end(); ++it)
        std::cout << *it << ' ';
    std::cout << '\n';
    return 0;
}
```

What does the following program print?

```cpp
#include <iostream>
#include <array>
int main()
{
    std::array<int, 3> a { 4, 5, 6 };
    for (auto it = a.begin(); it != a.end(); ++it)
        *it += 1;
    for (auto it = a.begin(); it != a.end(); ++it)
        std::cout << *it << ' ';
    std::cout << '\n';
    return 0;
}
```
